#include<iostream> 
using namespace std;
int main()
{
    int n;
    cin>>n;
    char a='A';
    for(int i=0;i<=n-1;i++)
    {
        for(int j=0;j<=i;j++)
        {
            cout<<a;
            a++;
            if(a>'Z')
            {
                a='A';
            }
        }
        cout<<endl;
    }
    return 0;
}
